import android.content.Context
import android.content.SharedPreferences

class AuthenticationManager(private val context: Context) {
    
    private val sharedPrefName = "UserAuth"
    private var sharedPref: SharedPreferences? = null

    init {
        sharedPref = context.getSharedPreferences(sharedPrefName, Context.MODE_PRIVATE)
    }

    fun saveAuthentication(userId: String?, authToken: String?) {
        val editor = sharedPref?.edit()
        if (editor != null) {
            editor.putString("UserId", userId)
            editor.putString("AuthToken", authToken)
            editor.apply()
        }
    }
    
    fun getAuthentication(): Pair<String?, String?>? {
        return sharedPref?.let { 
            it.getString("UserId", null)?.let { userId -> 
                it.getString("AuthToken", null) to userId
            } 
        }
    }
}